mapper.select:
select dept_id
from teacher
where user_id = #{userId}

SELECT u.user_id, u.nickname, u.user_type, u.identity, u.email, u.phone, u.sex, u.avatar, u.password, u.user_status, u.create_time, t.teacher_id, t.teacher_name, t.dept_id, t.title, t.office, t.admit_time, t.position_status FROM teacher t LEFT JOIN sys_user u ON u.user_id = t.user_id
AND u.nickname LIKE CONCAT('%', #{teacherUser.nickname}, '%')
AND t.teacher_name LIKE CONCAT('%', #{teacherUser.teacherName}, '%')
AND t.dept_id = #{teacherUser.deptId}
AND t.position_status = #{teacherUser.positionStatus}
ORDER BY u.create_time DESC
